#!/usr/bin/env bash
set -euo pipefail

APP_NAME="laravel-dev"
VERSION="1.0.0"
EXPECTED_SHA256="bfd5ec327a334f6bcbd30e6369dd3ea8721d2ec33676a6947fd0c7b3e6458328"

if [[ ${EUID:-$UID} -eq 0 ]]; then
  echo "Please run as regular user (installer will use sudo when needed)."
  exit 1
fi

if ! command -v sudo >/dev/null 2>&1; then
  echo "sudo is required."
  exit 1
fi

TMP_DIR="$(mktemp -d)"
cleanup() {
  rm -rf "$TMP_DIR"
}
trap cleanup EXIT

PAYLOAD_TGZ="$TMP_DIR/payload.tgz"
awk '/^__PAYLOAD_BELOW__$/ {found=1; next} found {print}' "$0" | base64 -d > "$PAYLOAD_TGZ"

ACTUAL_SHA256="$(sha256sum "$PAYLOAD_TGZ" | awk '{print $1}')"
if [[ "$ACTUAL_SHA256" != "$EXPECTED_SHA256" ]]; then
  echo "Checksum verification failed. Installer may be corrupted or modified."
  exit 1
fi

EXTRACT_DIR="$TMP_DIR/extracted"
mkdir -p "$EXTRACT_DIR"
tar -xzf "$PAYLOAD_TGZ" -C "$EXTRACT_DIR"

SRC_DIR="$EXTRACT_DIR/laravel-dev-1.0.0"
if [[ ! -d "$SRC_DIR" ]]; then
  echo "Invalid payload content."
  exit 1
fi

cd "$SRC_DIR"
chmod +x install.sh
./install.sh

echo "Installed $APP_NAME v$VERSION successfully."
echo "Run: laravel-dev app"
exit 0

__PAYLOAD_BELOW__

